// Domain/Entities/BaseEntity.cs
public abstract class BaseEntity
{
    public Guid Id { get; protected set; } = Guid.NewGuid();
    public DateTime CreatedAt { get; protected set; } = DateTime.UtcNow;
    public DateTime UpdatedAt { get; protected set; } = DateTime.UtcNow;

    private readonly List<IDomainEvent> _domainEvents = new();
    public IReadOnlyCollection<IDomainEvent> DomainEvents => _domainEvents.AsReadOnly();

    public void AddDomainEvent(IDomainEvent e) => _domainEvents.Add(e);
    public void ClearDomainEvents() => _domainEvents.Clear();
}

// Domain/Entities/User.cs
public class User : BaseEntity
{
    public string Name { get; private set; } = string.Empty;
    public Email Email { get; private set; } = null!;
    public string PasswordHash { get; private set; } = string.Empty;
    public UserRole Role { get; private set; }
    public bool IsActive { get; private set; } = true;

    private User() { } // For EF Core

    public static User Create(string name, Email email, string passwordHash)
    {
        var user = new User { Name = name, Email = email, PasswordHash = passwordHash };
        user.AddDomainEvent(new UserCreatedEvent(user.Id, email.Value));
        return user;
    }

    public void Promote()
    {
        if (Role == UserRole.Admin)
            throw new DomainException("User is already an admin");
        Role = UserRole.Admin;
        AddDomainEvent(new UserPromotedEvent(Id));
    }

    public void Deactivate()
    {
        IsActive = false;
        AddDomainEvent(new UserDeactivatedEvent(Id));
    }
}

// Domain/ValueObjects/Email.cs
public sealed class Email : ValueObject
{
    public string Value { get; }
    private Email(string value) => Value = value;

    public static Email Create(string email)
    {
        if (string.IsNullOrWhiteSpace(email))
            throw new DomainException("Email cannot be empty");
        if (!IsValidEmail(email))
            throw new DomainException("Invalid email format");
        return new Email(email.ToLowerInvariant());
    }

    protected override IEnumerable<object> GetEqualityComponents() { yield return Value; }
    public static implicit operator string(Email e) => e.Value;
}
